function isBalanced(root) {
  return height(root) !== -1;
}
function height(root) {
  if (!root) return 0;
  const l = height(root.left);
  if (l === -1) return -1;
  const r = height(root.right);
  if (r === -1) return -1;
  if (Math.abs(l - r) > 1) return -1;
  return Math.max(l, r) + 1;
}
