// 强制使用 WASM 后端（用于不支持 WebGPU 的环境）
env.backends.onnx ??= {};
env.backends.onnx.executionProviders = ['wasm'];
env.backends.onnx.wasm ??= {};
env.backends.onnx.wasm.numThreads = navigator.hardwareConcurrency;
env.backends.onnx.wasm.simd = true;

// 自动降级策略
async function createPipeline(task: string, model: string) {
  try {
    return await pipeline(task, model, { device: 'webgpu' });
  } catch {
    console.warn('WebGPU 不可用，降级至 WASM');
    env.backends.onnx ??= {}; env.backends.onnx.executionProviders = ['wasm'];
    return await pipeline(task, model);
  }
}
