    SK --> Plugins["Plugins<br/>插件系统"]
    SK --> Memory["Memory<br/>记忆系统"]
    SK --> Connectors["Connectors<br/>连接器"]
    
    Planner --> P1["顺序规划"]
    Planner --> P2["步骤规划"]
    Planner --> P3["自定义规划"]
    
    Plugins --> PL1["Native Plugin<br/>原生代码"]
    Plugins --> PL2["Semantic Plugin<br/>LLM Prompt"]
    
    Memory --> M1["语义记忆"]
